const e=JSON.parse('{"key":"v-353e952a","path":"/posts/%E4%BB%80%E4%B9%88%E6%98%AFLess.html","title":"什么是Less","lang":"zh-CN","frontmatter":{"title":"什么是Less","isTimeLine":true,"date":"2026-03-10T00:00:00.000Z","category":["前端","Less"],"tag":["Less"]},"headers":[{"level":3,"title":"什么是Less","slug":"什么是less","link":"#什么是less","children":[]},{"level":3,"title":"变量","slug":"变量","link":"#变量","children":[]},{"level":3,"title":"混入","slug":"混入","link":"#混入","children":[]},{"level":3,"title":"嵌套","slug":"嵌套","link":"#嵌套","children":[]},{"level":3,"title":"运算函数","slug":"运算函数","link":"#运算函数","children":[]},{"level":3,"title":"作用域","slug":"作用域","link":"#作用域","children":[]},{"level":3,"title":"继承","slug":"继承","link":"#继承","children":[]},{"level":3,"title":"导入","slug":"导入","link":"#导入","children":[]}],"git":{"createdTime":1773238261000,"updatedTime":1773238261000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":3.3,"words":990},"filePathRelative":"posts/什么是Less.md","localizedDate":"2026年3月10日","excerpt":"<h3> 什么是Less</h3>\\n<ol>\\n<li>全称（Leaner Style Sheets）是一种css预处理语言，支持变量、函数、混合、嵌套、循环等特点。</li>\\n<li>是css，在css基础上多了一些东西。引入了变量、混入、嵌套、运算、函数等功能，浏览器不认识需要编译成css让浏览器识别。</li>\\n<li>如何编译？</li>\\n</ol>\\n<blockquote>\\n<ul>\\n<li>第一种与nodejs一起使用，用lessc命令编译lessc styles.less styles.css</li>\\n<li>第二种使用浏览器，引入less的cdn<br>\\n<code> &lt;link rel=\\"stylesheet/less\\" type=\\"text/css\\" href=\\"styles.less\\" /&gt;&lt;script src=\\"https://cdn.jsdelivr.net/npm/less\\" &gt;&lt;/script&gt;</code></li>\\n<li>第三种vscode插件编译：<br>\\nⅰ. vscode中安装less编译插件：Easy Less 插件。<br>\\nⅱ. 安装成功后重启vscode软件，新建.less后缀名文件，保存后会自动生成对应.css文件。</li>\\n</ul>\\n</blockquote>"}');export{e as data};
